import type { NextFunction, Request, Response } from 'express';
import type { RoleName } from '../auth/roles';

export const requireAuth = (request: Request, response: Response, next: NextFunction): void => {
  if (!request.auth) {
    response.status(401).json({ error: 'Authentication required.' });
    return;
  }
  next();
};

export const requireRoles = (...allowedRoles: RoleName[]) => {
  return (request: Request, response: Response, next: NextFunction): void => {
    if (!request.auth) {
      response.status(401).json({ error: 'Authentication required.' });
      return;
    }

    const hasAllowedRole = request.auth.roles.some((role) =>
      allowedRoles.includes(role)
    );

    if (!hasAllowedRole) {
      response.status(403).json({ error: 'Forbidden for this role.' });
      return;
    }

    next();
  };
};

import { apiRequest } from "./client";
import type { AuthUser } from "../types/auth";

type MeResponse = {
  user: AuthUser;
  expiresAt: string;
};

type LoginResponse = MeResponse;

type SuccessEnvelope<T> = {
  success: true;
  data: T;
};

const unwrap = <T>(payload: T | SuccessEnvelope<T>): T => {
  if (
    payload &&
    typeof payload === "object" &&
    "success" in payload &&
    (payload as { success?: unknown }).success === true &&
    "data" in payload
  ) {
    return (payload as SuccessEnvelope<T>).data;
  }

  return payload as T;
};

export const authApi = {
  login: async (payload: { username: string; password: string }) =>
    unwrap(
      await apiRequest<LoginResponse | SuccessEnvelope<LoginResponse>>(
        "/auth/login",
        {
          method: "POST",
          body: JSON.stringify(payload),
        },
      ),
    ),
  me: async () =>
    unwrap(
      await apiRequest<MeResponse | SuccessEnvelope<MeResponse>>("/auth/me"),
    ),
  logout: () => apiRequest<void>("/auth/logout", { method: "POST" }),
};

import type { Request, Response, NextFunction } from 'express';
import type { AuthService } from '../auth/authService';
import { env } from '../config/env';

export const sessionCookieName = 'neighborhoodpickup_session';

const parseCookieValue = (cookieHeader: string | undefined, key: string): string | undefined => {
  if (!cookieHeader) {
    return undefined;
  }

  const segments = cookieHeader.split(';').map((part) => part.trim());
  const target = segments.find((segment) => segment.startsWith(`${key}=`));

  if (!target) {
    return undefined;
  }

  return decodeURIComponent(target.substring(key.length + 1));
};

export const setSessionCookie = (
  response: Response,
  token: string,
  expiresAt: Date
): void => {
  response.cookie(sessionCookieName, encodeURIComponent(token), {
    httpOnly: true,
    sameSite: 'lax',
    secure: env.isProduction,
    expires: expiresAt
  });
};

export const clearSessionCookie = (response: Response): void => {
  response.clearCookie(sessionCookieName, {
    httpOnly: true,
    sameSite: 'lax',
    secure: env.isProduction
  });
};

export const authSessionMiddleware = (authService: AuthService) => {
  return async (request: Request, _response: Response, next: NextFunction) => {
    const token = parseCookieValue(request.headers.cookie, sessionCookieName);

    if (!token) {
      return next();
    }

    try {
      const session = await authService.getCurrentSession(token);
      if (session) {
        request.auth = {
          userId: session.userId,
          username: session.username,
          roles: session.roles,
          tokenHash: 'resolved'
        };
      }
      return next();
    } catch (error) {
      return next(error);
    }
  };
};

export const readSessionToken = (request: Request): string | undefined => {
  return parseCookieValue(request.headers.cookie, sessionCookieName);
};

import { Router } from "express";
import { z } from "zod";
import { AuthService } from "../auth/authService";
import { MySqlAuthStore } from "../auth/mysqlAuthStore";
import { sendError, sendSuccess } from "../utils/apiResponse";
import {
  clearSessionCookie,
  readSessionToken,
  setSessionCookie,
} from "../middleware/sessionAuth";

const loginSchema = z.object({
  username: z.string().min(1),
  password: z.string().min(1),
});

const authService = new AuthService(new MySqlAuthStore());

export const authRouter = Router();

authRouter.post("/login", async (request, response, next) => {
  try {
    const parsed = loginSchema.safeParse(request.body);
    if (!parsed.success) {
      sendError(response, 400, "Invalid login payload.", "INVALID_PAYLOAD");
      return;
    }

    const result = await authService.login({
      username: parsed.data.username,
      password: parsed.data.password,
      ipAddress: request.ip,
      userAgent: request.headers["user-agent"],
    });

    if (!result.ok) {
      const status = result.code === "LOCKED" ? 423 : 401;
      sendError(response, status, result.message, result.code, {
        lockedUntil: result.lockedUntil?.toISOString(),
      });
      return;
    }

    setSessionCookie(response, result.token, result.expiresAt);

    sendSuccess(response, {
      user: result.user,
      expiresAt: result.expiresAt.toISOString(),
    });
  } catch (error) {
    next(error);
  }
});

authRouter.post("/logout", async (request, response, next) => {
  try {
    const token = readSessionToken(request);
    await authService.logout(token);
    clearSessionCookie(response);
    response.status(204).send();
  } catch (error) {
    next(error);
  }
});

authRouter.get("/me", async (request, response, next) => {
  try {
    const token = readSessionToken(request);
    const session = await authService.getCurrentSession(token);

    if (!session) {
      sendError(response, 401, "Not authenticated.", "NOT_AUTHENTICATED");
      return;
    }

    sendSuccess(response, {
      user: {
        id: session.userId,
        username: session.username,
        roles: session.roles,
      },
      expiresAt: session.expiresAt.toISOString(),
    });
  } catch (error) {
    next(error);
  }
});

const apiBaseUrl = import.meta.env.VITE_API_BASE_URL ?? "http://localhost:4000";

const statusMessages: Record<number, string> = {
  400: "The request was invalid. Please check your input and try again.",
  401: "Your session has expired. Please sign in again.",
  403: "You are not allowed to perform this action.",
  404: "The requested resource was not found.",
  409: "The request conflicts with the current state of the data.",
  422: "Some fields failed validation. Please review and try again.",
  429: "Too many requests. Please wait a moment and try again.",
  500: "The server encountered an internal error. Please try again shortly.",
  502: "The service is temporarily unavailable. Please try again shortly.",
  503: "The service is temporarily unavailable. Please try again shortly.",
  504: "The server took too long to respond. Please try again.",
};

const sanitizeMessage = (value: string): string =>
  value
    .replace(/[\u0000-\u001F\u007F]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const tryUnwrapSuccessEnvelope = <T>(payload: unknown): T | undefined => {
  if (!payload || typeof payload !== "object") {
    return undefined;
  }

  const maybeEnvelope = payload as {
    success?: unknown;
    data?: unknown;
  };

  if (
    "data" in maybeEnvelope &&
    "success" in maybeEnvelope &&
    maybeEnvelope.success !== false
  ) {
    return maybeEnvelope.data as T;
  }

  if (maybeEnvelope.success === true && "data" in maybeEnvelope) {
    return maybeEnvelope.data as T;
  }

  return undefined;
};

const extractDetailMessage = (payload: unknown): string | undefined => {
  if (!payload || typeof payload !== "object") {
    return undefined;
  }

  const typed = payload as {
    error?: unknown;
    message?: unknown;
    details?: unknown;
    success?: unknown;
  };

  if (
    typed.success === false &&
    typed.error &&
    typeof typed.error === "object"
  ) {
    const wrappedError = typed.error as {
      message?: unknown;
      details?: unknown;
    };

    if (
      typeof wrappedError.message === "string" &&
      wrappedError.message.trim().length > 0
    ) {
      return wrappedError.message;
    }

    if (Array.isArray(wrappedError.details)) {
      const firstIssue = wrappedError.details.find(
        (issue) =>
          issue &&
          typeof issue === "object" &&
          "message" in issue &&
          typeof (issue as { message?: unknown }).message === "string",
      ) as { message: string } | undefined;

      if (firstIssue) {
        return firstIssue.message;
      }
    }
  }

  if (typeof typed.error === "string" && typed.error.trim().length > 0) {
    return typed.error;
  }

  if (typeof typed.message === "string" && typed.message.trim().length > 0) {
    return typed.message;
  }

  if (Array.isArray(typed.details)) {
    const firstIssue = typed.details.find(
      (issue) =>
        issue &&
        typeof issue === "object" &&
        "message" in issue &&
        typeof (issue as { message?: unknown }).message === "string",
    ) as { message: string } | undefined;

    if (firstIssue) {
      return firstIssue.message;
    }
  }

  return undefined;
};

const buildErrorMessage = (
  status: number,
  path: string,
  payload: unknown,
): string => {
  const fallback =
    statusMessages[status] ?? `Request failed with status ${status}.`;
  const detail = extractDetailMessage(payload);

  if (!detail) {
    return `${fallback} (endpoint: ${path})`;
  }

  return `${fallback} ${sanitizeMessage(detail)} (endpoint: ${path})`;
};

const parsePayload = async (response: Response): Promise<unknown> => {
  const rawText = await response.text();
  if (rawText.length === 0) {
    return undefined;
  }

  const contentType = (
    response.headers.get("content-type") ?? ""
  ).toLowerCase();
  const looksLikeJson =
    contentType.includes("application/json") || /^[\[{]/.test(rawText.trim());

  if (!looksLikeJson) {
    return rawText;
  }

  try {
    return JSON.parse(rawText);
  } catch {
    return rawText;
  }
};

export class ApiError extends Error {
  public readonly status: number;
  public readonly payload: unknown;

  public constructor(message: string, status: number, payload: unknown) {
    super(message);
    this.status = status;
    this.payload = payload;
  }
}

export const apiRequest = async <T>(
  path: string,
  options?: RequestInit,
): Promise<T> => {
  const mergedHeaders = new Headers(options?.headers ?? {});
  const body = options?.body;
  const shouldSetJsonContentType =
    body !== undefined &&
    body !== null &&
    typeof body === "string" &&
    !mergedHeaders.has("Content-Type");

  if (!mergedHeaders.has("Accept")) {
    mergedHeaders.set(
      "Accept",
      "application/json, text/plain;q=0.9, */*;q=0.8",
    );
  }

  if (shouldSetJsonContentType) {
    mergedHeaders.set("Content-Type", "application/json");
  }

  let response: Response;
  try {
    response = await fetch(`${apiBaseUrl}${path}`, {
      credentials: "include",
      ...options,
      headers: mergedHeaders,
    });
  } catch {
    throw new ApiError(
      `Unable to reach the server. Check your network connection and confirm the API is running. (endpoint: ${path})`,
      0,
      null,
    );
  }

  if (response.status === 204) {
    return undefined as T;
  }

  const payload = await parsePayload(response);

  if (!response.ok) {
    const message = buildErrorMessage(response.status, path, payload);
    throw new ApiError(message, response.status, payload);
  }

  const unwrapped = tryUnwrapSuccessEnvelope<T>(payload);
  if (unwrapped !== undefined) {
    return unwrapped;
  }

  return payload as T;
};

