import { apiRequest } from "./client";
import type {
  BlacklistRecord,
  CommissionRow,
  WithdrawalEligibility,
  WithdrawalRecord,
} from "../types/finance";

export const financeApi = {
  getCommissions: (params?: { dateFrom?: string; dateTo?: string }) => {
    const query = new URLSearchParams();
    if (params?.dateFrom) {
      query.set("dateFrom", params.dateFrom);
    }
    if (params?.dateTo) {
      query.set("dateTo", params.dateTo);
    }
    const suffix = query.toString() ? `?${query.toString()}` : "";
    return apiRequest<{ data: CommissionRow[] }>(
      `/finance/commissions${suffix}`,
    );
  },
  getWithdrawalEligibility: (leaderUserId?: number) => {
    const suffix = leaderUserId ? `?leaderUserId=${leaderUserId}` : "";
    return apiRequest<WithdrawalEligibility>(
      `/finance/withdrawals/eligibility${suffix}`,
    );
  },
  requestWithdrawal: (payload: { amount: number; leaderUserId?: number }) =>
    apiRequest<WithdrawalRecord>("/finance/withdrawals", {
      method: "POST",
      body: JSON.stringify(payload),
    }),
  getReconciliationCsv: async (params: {
    dateFrom: string;
    dateTo: string;
  }) => {
    const query = new URLSearchParams({
      dateFrom: params.dateFrom,
      dateTo: params.dateTo,
    });

    const response = await fetch(
      `${import.meta.env.VITE_API_BASE_URL ?? "http://localhost:4000"}/finance/reconciliation/export?${query.toString()}`,
      {
        credentials: "include",
      },
    );

    if (!response.ok) {
      const payload = await response.text();
      throw new Error(payload || `Request failed with ${response.status}`);
    }

    return response.text();
  },
  listBlacklist: () =>
    apiRequest<{ data: BlacklistRecord[] }>("/admin/withdrawal-blacklist"),
  upsertBlacklist: (payload: {
    userId: number;
    reason: string;
    active?: boolean;
  }) =>
    apiRequest<{ ok: true }>("/admin/withdrawal-blacklist", {
      method: "POST",
      body: JSON.stringify(payload),
    }),
  patchBlacklist: (
    id: number,
    payload: { reason?: string; active?: boolean },
  ) =>
    apiRequest<{ ok: true }>(`/admin/withdrawal-blacklist/${id}`, {
      method: "PATCH",
      body: JSON.stringify(payload),
    }),
  deleteBlacklist: (id: number) =>
    apiRequest<void>(`/admin/withdrawal-blacklist/${id}`, {
      method: "DELETE",
    }),
};

import { env } from '../config/env';
import { generateSessionToken, hashToken } from './sessionToken';
import { verifyPassword } from './passwordHash';
import type { AuthStore, AuthUser, SessionRecord } from './types';

const lockoutWindowMs = env.lockoutMinutes * 60 * 1000;

type LoginResult =
  | {
      ok: true;
      user: Pick<AuthUser, 'id' | 'username' | 'roles'>;
      token: string;
      expiresAt: Date;
    }
  | {
      ok: false;
      code: 'INVALID_CREDENTIALS' | 'LOCKED' | 'INACTIVE';
      message: string;
      lockedUntil?: Date;
    };

export class AuthService {
  public constructor(private readonly store: AuthStore) {}

  public async login(params: {
    username: string;
    password: string;
    ipAddress?: string;
    userAgent?: string;
  }): Promise<LoginResult> {
    const username = params.username.trim();
    const lockout = await this.getLockoutInfo(username);
    if (lockout.isLocked) {
      return {
        ok: false,
        code: 'LOCKED',
        message: 'Account is temporarily locked due to repeated failed login attempts.',
        lockedUntil: lockout.lockedUntil
      };
    }

    const user = await this.store.findUserByUsername(username);

    if (!user) {
      await this.store.recordAuthAttempt({
        username,
        success: false,
        ipAddress: params.ipAddress,
        userAgent: params.userAgent
      });
      return {
        ok: false,
        code: 'INVALID_CREDENTIALS',
        message: 'Invalid username or password.'
      };
    }

    if (!user.isActive) {
      return {
        ok: false,
        code: 'INACTIVE',
        message: 'Account is inactive.'
      };
    }

    const passwordValid = await verifyPassword(user.passwordHash, params.password);

    if (!passwordValid) {
      await this.store.recordAuthAttempt({
        username,
        success: false,
        ipAddress: params.ipAddress,
        userAgent: params.userAgent
      });

      const newLockout = await this.getLockoutInfo(username);
      if (newLockout.isLocked) {
        return {
          ok: false,
          code: 'LOCKED',
          message:
            'Account is temporarily locked due to repeated failed login attempts.',
          lockedUntil: newLockout.lockedUntil
        };
      }

      return {
        ok: false,
        code: 'INVALID_CREDENTIALS',
        message: 'Invalid username or password.'
      };
    }

    await this.store.recordAuthAttempt({
      username,
      success: true,
      ipAddress: params.ipAddress,
      userAgent: params.userAgent
    });

    const token = generateSessionToken();
    const tokenHash = hashToken(token, env.sessionSecret);
    const expiresAt = new Date(Date.now() + env.sessionTtlHours * 60 * 60 * 1000);

    await this.store.createSession({
      userId: user.id,
      tokenHash,
      expiresAt
    });

    return {
      ok: true,
      user: {
        id: user.id,
        username: user.username,
        roles: user.roles
      },
      token,
      expiresAt
    };
  }

  public async getCurrentSession(token: string | undefined): Promise<SessionRecord | null> {
    if (!token) {
      return null;
    }

    const tokenHash = hashToken(token, env.sessionSecret);
    const session = await this.store.findSessionByTokenHash(tokenHash);
    if (!session) {
      return null;
    }

    await this.store.touchSession(tokenHash);
    return session;
  }

  public async logout(token: string | undefined): Promise<void> {
    if (!token) {
      return;
    }
    const tokenHash = hashToken(token, env.sessionSecret);
    await this.store.revokeSession(tokenHash);
  }

  public async getLockoutInfo(username: string): Promise<{
    isLocked: boolean;
    lockedUntil?: Date;
  }> {
    const attempts = await this.store.listRecentAttempts(username, env.lockoutMaxAttempts);
    if (attempts.length < env.lockoutMaxAttempts) {
      return { isLocked: false };
    }

    const recent = attempts.slice(0, env.lockoutMaxAttempts);
    const allFailed = recent.every((attempt) => !attempt.success);
    if (!allFailed) {
      return { isLocked: false };
    }

    const mostRecentAttempt = recent[0];
    const lockedUntil = new Date(mostRecentAttempt.attemptedAt.getTime() + lockoutWindowMs);

    if (lockedUntil.getTime() <= Date.now()) {
      return { isLocked: false };
    }

    return { isLocked: true, lockedUntil };
  }
}

import { Router, type Response } from 'express';
import { z } from 'zod';
import { requireAuth, requireRoles } from '../../../middleware/rbac';
import {
  getLeaderDashboard,
  getMyLeaderApplication,
  getPendingLeaderApplications,
  reviewLeaderApplication,
  submitLeaderApplication
} from '../services/leaderService';

const createApplicationSchema = z.object({
  fullName: z.string().trim().min(3).max(120),
  phone: z.string().trim().min(6).max(32),
  experienceSummary: z.string().trim().min(20).max(4000),
  pickupPointId: z.coerce.number().int().positive().optional(),
  requestedCommissionEligible: z.boolean().default(false)
});

const decisionSchema = z.object({
  decision: z.enum(['APPROVE', 'REJECT']),
  reason: z.string().trim().min(3).max(255),
  commissionEligible: z.boolean().default(false)
});

const dashboardQuerySchema = z.object({
  dateFrom: z.string().date().optional(),
  dateTo: z.string().date().optional()
});

const handleLeaderError = (error: unknown, response: Response): boolean => {
  if (error instanceof z.ZodError) {
    response.status(400).json({ error: 'Invalid request payload.', details: error.issues });
    return true;
  }

  if (error instanceof Error && error.message === 'LEADER_APPLICATION_ALREADY_PENDING') {
    response.status(409).json({ error: 'A pending application already exists for this leader.' });
    return true;
  }

  if (error instanceof Error && error.message === 'LEADER_APPLICATION_NOT_FOUND') {
    response.status(404).json({ error: 'Leader application not found.' });
    return true;
  }

  if (error instanceof Error && error.message === 'LEADER_APPLICATION_ALREADY_REVIEWED') {
    response.status(409).json({ error: 'Leader application has already been reviewed.' });
    return true;
  }

  return false;
};

export const leaderRouter = Router();

leaderRouter.post('/leaders/applications', requireAuth, requireRoles('GROUP_LEADER'), async (request, response, next) => {
  try {
    const payload = createApplicationSchema.parse(request.body);
    const result = await submitLeaderApplication({
      userId: request.auth!.userId,
      input: payload
    });
    response.status(201).json(result);
  } catch (error) {
    if (handleLeaderError(error, response)) {
      return;
    }
    next(error);
  }
});

leaderRouter.get('/leaders/applications/me', requireAuth, requireRoles('GROUP_LEADER'), async (request, response, next) => {
  try {
    const result = await getMyLeaderApplication(request.auth!.userId);
    response.json({ data: result });
  } catch (error) {
    if (handleLeaderError(error, response)) {
      return;
    }
    next(error);
  }
});

leaderRouter.get('/admin/leaders/applications/pending', requireAuth, requireRoles('ADMINISTRATOR'), async (_request, response, next) => {
  try {
    const data = await getPendingLeaderApplications();
    response.json({ data });
  } catch (error) {
    if (handleLeaderError(error, response)) {
      return;
    }
    next(error);
  }
});

leaderRouter.post('/admin/leaders/applications/:id/decision', requireAuth, requireRoles('ADMINISTRATOR'), async (request, response, next) => {
  try {
    const applicationId = z.coerce.number().int().positive().parse(request.params.id);
    const payload = decisionSchema.parse(request.body);
    const result = await reviewLeaderApplication({
      applicationId,
      adminUserId: request.auth!.userId,
      input: payload
    });
    response.json(result);
  } catch (error) {
    if (handleLeaderError(error, response)) {
      return;
    }
    next(error);
  }
});

leaderRouter.get('/leaders/dashboard/metrics', requireAuth, requireRoles('GROUP_LEADER'), async (request, response, next) => {
  try {
    const query = dashboardQuerySchema.parse(request.query);
    const data = await getLeaderDashboard({
      leaderUserId: request.auth!.userId,
      dateFrom: query.dateFrom,
      dateTo: query.dateTo
    });

    if (!data) {
      response.status(404).json({ error: 'Leader record not found. Apply for onboarding first.' });
      return;
    }

    response.json(data);
  } catch (error) {
    if (handleLeaderError(error, response)) {
      return;
    }
    next(error);
  }
});

import { apiRequest } from './client';
import type { LeaderApplicationRecord, LeaderDashboardMetrics } from '../types/leaders';

export const leaderApi = {
  createApplication: (payload: {
    fullName: string;
    phone: string;
    experienceSummary: string;
    pickupPointId?: number;
    requestedCommissionEligible: boolean;
  }) =>
    apiRequest<LeaderApplicationRecord>('/leaders/applications', {
      method: 'POST',
      body: JSON.stringify(payload)
    }),

  getMyApplication: () =>
    apiRequest<{ data: LeaderApplicationRecord | null }>('/leaders/applications/me'),

  getPendingApplications: () =>
    apiRequest<{ data: LeaderApplicationRecord[] }>('/admin/leaders/applications/pending'),

  decideApplication: (
    applicationId: number,
    payload: { decision: 'APPROVE' | 'REJECT'; reason: string; commissionEligible: boolean }
  ) =>
    apiRequest<{
      id: number;
      leaderApplicationId: number;
      decision: 'APPROVED' | 'REJECTED';
      reason: string;
    }>(`/admin/leaders/applications/${applicationId}/decision`, {
      method: 'POST',
      body: JSON.stringify(payload)
    }),

  getDashboardMetrics: (params?: { dateFrom?: string; dateTo?: string }) => {
    const query = new URLSearchParams();
    if (params?.dateFrom) {
      query.set('dateFrom', params.dateFrom);
    }
    if (params?.dateTo) {
      query.set('dateTo', params.dateTo);
    }
    const suffix = query.toString() ? `?${query.toString()}` : '';
    return apiRequest<LeaderDashboardMetrics>(`/leaders/dashboard/metrics${suffix}`);
  }
};

import { dbPool } from '../db/pool';
import type { AuthAttemptRecord, AuthStore, AuthUser, SessionRecord } from './types';
import type { RoleName } from './roles';

const getRolesForUser = async (userId: number): Promise<RoleName[]> => {
  const [roleRows] = await dbPool.query<{ name: RoleName }[]>(
    `SELECT r.name
     FROM roles r
     JOIN user_roles ur ON ur.role_id = r.id
     WHERE ur.user_id = ?`,
    [userId]
  );
  return roleRows.map((row: { name: RoleName }) => row.name);
};

export class MySqlAuthStore implements AuthStore {
  public async findUserByUsername(username: string): Promise<AuthUser | null> {
    const [rows] = await dbPool.query<
      { id: number; username: string; password_hash: string; is_active: number }[]
    >(
      `SELECT id, username, password_hash, is_active
       FROM users
       WHERE username = ?
       LIMIT 1`,
      [username]
    );

    const row = rows[0];
    if (!row) {
      return null;
    }

    const roles = await getRolesForUser(row.id);

    return {
      id: row.id,
      username: row.username,
      passwordHash: row.password_hash,
      isActive: row.is_active === 1,
      roles
    };
  }

  public async findUserById(userId: number): Promise<AuthUser | null> {
    const [rows] = await dbPool.query<
      { id: number; username: string; password_hash: string; is_active: number }[]
    >(
      `SELECT id, username, password_hash, is_active
       FROM users
       WHERE id = ?
       LIMIT 1`,
      [userId]
    );

    const row = rows[0];
    if (!row) {
      return null;
    }

    const roles = await getRolesForUser(row.id);

    return {
      id: row.id,
      username: row.username,
      passwordHash: row.password_hash,
      isActive: row.is_active === 1,
      roles
    };
  }

  public async listRecentAttempts(
    username: string,
    limit: number
  ): Promise<AuthAttemptRecord[]> {
    const [rows] = await dbPool.query<{ success: number; attempted_at: Date | string }[]>(
      `SELECT success, attempted_at
       FROM auth_attempts
       WHERE username = ?
       ORDER BY attempted_at DESC
       LIMIT ?`,
      [username, limit]
    );

    return rows.map((row: { success: number; attempted_at: Date | string }) => ({
