import { createApp } from "vue";
import { createPinia } from "pinia";
import App from "./App.vue";
import { registerApiAuthFailureHandler } from "./api/client";
import { router } from "./router";
import { useAuthStore } from "./stores/authStore";
import "./styles.css";

const app = createApp(App);
const pinia = createPinia();

let authRedirectInFlight: Promise<void> | null = null;

registerApiAuthFailureHandler((context) => {
  if (authRedirectInFlight) {
    return authRedirectInFlight;
  }

  const authStore = useAuthStore(pinia);

  authRedirectInFlight = (async () => {
    const currentRoute = router.currentRoute.value;

    if (context.status === 401) {
      authStore.clearSession();
      if (currentRoute.path !== "/login") {
        await router.replace({
          path: "/login",
          query: {
            reason: "session-expired",
            redirect: currentRoute.fullPath,
          },
        });
      }
      return;
    }

    if (context.status === 403 && currentRoute.path !== "/forbidden") {
      await router.replace({
        path: "/forbidden",
        query: {
          from: currentRoute.fullPath,
        },
      });
    }
  })().finally(() => {
    authRedirectInFlight = null;
  });

  return authRedirectInFlight;
});

app.use(pinia);
app.use(router);
app.mount("#app");

const apiBaseUrl = import.meta.env.VITE_API_BASE_URL ?? "http://localhost:4000";

const statusMessages: Record<number, string> = {
  400: "The request was invalid. Please check your input and try again.",
  401: "Your session has expired. Please sign in again.",
  403: "You are not allowed to perform this action.",
  404: "The requested resource was not found.",
  409: "The request conflicts with the current state of the data.",
  422: "Some fields failed validation. Please review and try again.",
  429: "Too many requests. Please wait a moment and try again.",
  500: "The server encountered an internal error. Please try again shortly.",
  502: "The service is temporarily unavailable. Please try again shortly.",
  503: "The service is temporarily unavailable. Please try again shortly.",
  504: "The server took too long to respond. Please try again.",
};

const handledAuthorizationCodes = new Set([
  "ROLE_FORBIDDEN",
  "APPEAL_FORBIDDEN",
  "APPEAL_STATUS_FORBIDDEN",
  "THREAD_FORBIDDEN",
]);

export type ApiAuthFailureContext = {
  status: number;
  path: string;
  code?: string;
  payload: unknown;
};

type ApiAuthFailureHandler = (
  context: ApiAuthFailureContext,
) => void | Promise<void>;

let authFailureHandler: ApiAuthFailureHandler | null = null;

export const registerApiAuthFailureHandler = (
  handler: ApiAuthFailureHandler | null,
): void => {
  authFailureHandler = handler;
};

const sanitizeMessage = (value: string): string =>
  value
    .replace(/[\u0000-\u001F\u007F]/g, " ")
    .replace(/\s+/g, " ")
    .trim();

const tryUnwrapSuccessEnvelope = <T>(payload: unknown): T | undefined => {
  if (!payload || typeof payload !== "object") {
    return undefined;
  }

  const maybeEnvelope = payload as {
    success?: unknown;
    data?: unknown;
  };

  if (
    "data" in maybeEnvelope &&
    "success" in maybeEnvelope &&
    maybeEnvelope.success !== false
  ) {
    return maybeEnvelope.data as T;
  }

  if (maybeEnvelope.success === true && "data" in maybeEnvelope) {
    return maybeEnvelope.data as T;
  }

  return undefined;
};

const extractDetailMessage = (payload: unknown): string | undefined => {
  if (!payload || typeof payload !== "object") {
    return undefined;
  }

  const typed = payload as {
    error?: unknown;
    message?: unknown;
    details?: unknown;
    success?: unknown;
  };

  if (
    typed.success === false &&
    typed.error &&
    typeof typed.error === "object"
  ) {
    const wrappedError = typed.error as {
      message?: unknown;
      details?: unknown;
    };

    if (
      typeof wrappedError.message === "string" &&
      wrappedError.message.trim().length > 0
    ) {
      return wrappedError.message;
    }

    if (Array.isArray(wrappedError.details)) {
      const firstIssue = wrappedError.details.find(
        (issue) =>
          issue &&
          typeof issue === "object" &&
          "message" in issue &&
          typeof (issue as { message?: unknown }).message === "string",
      ) as { message: string } | undefined;

      if (firstIssue) {
        return firstIssue.message;
      }
    }
  }

  if (typeof typed.error === "string" && typed.error.trim().length > 0) {
    return typed.error;
  }

  if (typeof typed.message === "string" && typed.message.trim().length > 0) {
    return typed.message;
  }

  if (Array.isArray(typed.details)) {
    const firstIssue = typed.details.find(
      (issue) =>
        issue &&
        typeof issue === "object" &&
        "message" in issue &&
        typeof (issue as { message?: unknown }).message === "string",
    ) as { message: string } | undefined;

    if (firstIssue) {
      return firstIssue.message;
    }
  }

  return undefined;
};

const extractErrorCode = (payload: unknown): string | undefined => {
  if (!payload || typeof payload !== "object") {
    return undefined;
  }

  const typed = payload as {
    code?: unknown;
    error?: unknown;
  };

  if (typeof typed.code === "string" && typed.code.trim().length > 0) {
    return typed.code;
  }

  if (typed.error && typeof typed.error === "object") {
    const wrappedError = typed.error as { code?: unknown };
    if (
      typeof wrappedError.code === "string" &&
      wrappedError.code.trim().length > 0
    ) {
      return wrappedError.code;
    }
  }

  return undefined;
};

const shouldHandleAuthFailure = (context: ApiAuthFailureContext): boolean => {
  if (!authFailureHandler) {
    return false;
  }

  if (context.status === 401) {
    return context.path !== "/auth/login";
  }

  if (context.status !== 403) {
    return false;
  }

  return context.code ? handledAuthorizationCodes.has(context.code) : false;
};

const buildErrorMessage = (
  status: number,
  path: string,
  payload: unknown,
): string => {
  const fallback =
    statusMessages[status] ?? `Request failed with status ${status}.`;
  const detail = extractDetailMessage(payload);

  if (!detail) {
    return `${fallback} (endpoint: ${path})`;
  }

  return `${fallback} ${sanitizeMessage(detail)} (endpoint: ${path})`;
};

const parsePayload = async (response: Response): Promise<unknown> => {
  const rawText = await response.text();
  if (rawText.length === 0) {
    return undefined;
  }

  const contentType = (
    response.headers.get("content-type") ?? ""
  ).toLowerCase();
  const looksLikeJson =
    contentType.includes("application/json") || /^[\[{]/.test(rawText.trim());

  if (!looksLikeJson) {
    return rawText;
  }

  try {
    return JSON.parse(rawText);
  } catch {
    return rawText;
  }
};

export class ApiError extends Error {
  public readonly status: number;
  public readonly payload: unknown;
  public readonly code?: string;

  public constructor(
    message: string,
    status: number,
    payload: unknown,
    code?: string,
  ) {
    super(message);
    this.status = status;
    this.payload = payload;
    this.code = code;
  }
}

export const apiRequest = async <T>(
  path: string,
  options?: RequestInit,
): Promise<T> => {
  const mergedHeaders = new Headers(options?.headers ?? {});
  const body = options?.body;
  const shouldSetJsonContentType =
    body !== undefined &&
    body !== null &&
    typeof body === "string" &&
    !mergedHeaders.has("Content-Type");

  if (!mergedHeaders.has("Accept")) {
    mergedHeaders.set(
      "Accept",
      "application/json, text/plain;q=0.9, */*;q=0.8",
    );
  }

  if (shouldSetJsonContentType) {
    mergedHeaders.set("Content-Type", "application/json");
  }

  let response: Response;
  try {
    response = await fetch(`${apiBaseUrl}${path}`, {
      credentials: "include",
      ...options,
      headers: mergedHeaders,
    });
  } catch {
    throw new ApiError(
      `Unable to reach the server. Check your network connection and confirm the API is running. (endpoint: ${path})`,
      0,
      null,
    );
  }

  if (response.status === 204) {
    return undefined as T;
  }

  const payload = await parsePayload(response);

  if (!response.ok) {
    const code = extractErrorCode(payload);
    const message = buildErrorMessage(response.status, path, payload);
    const error = new ApiError(message, response.status, payload, code);

    if (shouldHandleAuthFailure({ status: response.status, path, code, payload })) {
      void Promise.resolve(
        authFailureHandler?.({ status: response.status, path, code, payload }),
      ).catch(() => undefined);
    }

    throw error;
  }

  const unwrapped = tryUnwrapSuccessEnvelope<T>(payload);
  if (unwrapped !== undefined) {
    return unwrapped;
  }

  return payload as T;
};

import type { RoleName } from "../types/auth";

export const roleHomePaths: Record<RoleName, string> = {
  MEMBER: "/home/member",
  GROUP_LEADER: "/home/group-leader",
  REVIEWER: "/home/reviewer",
  FINANCE_CLERK: "/home/finance-clerk",
  ADMINISTRATOR: "/home/administrator",
};

export const rolePriority: RoleName[] = [
  "ADMINISTRATOR",
  "FINANCE_CLERK",
  "REVIEWER",
  "GROUP_LEADER",
  "MEMBER",
];

export const roleDisplayNames: Record<RoleName, string> = {
  MEMBER: "Member",
  GROUP_LEADER: "Group Leader",
  REVIEWER: "Reviewer",
  FINANCE_CLERK: "Finance Clerk",
  ADMINISTRATOR: "Administrator",
};

export const resolvePrimaryRole = (
  roles: RoleName[],
): RoleName | null =>
  rolePriority.find((role) => roles.includes(role)) ?? roles[0] ?? null;

export const resolveRoleHomePath = (roles: RoleName[]): string | null => {
  const primaryRole = resolvePrimaryRole(roles);
  return primaryRole ? roleHomePaths[primaryRole] : null;
};

export const hasAnyRole = (
  userRoles: RoleName[],
  allowedRoles: RoleName[],
): boolean => allowedRoles.some((role) => userRoles.includes(role));

type AppNavItem = {
  label: string;
  to: string;
  roles: RoleName[];
};

const appNavItems: AppNavItem[] = [
  {
    label: "Workspace",
    to: "/home/administrator",
    roles: ["ADMINISTRATOR"],
  },
  {
    label: "Workspace",
    to: "/home/finance-clerk",
    roles: ["FINANCE_CLERK"],
  },
  {
    label: "Workspace",
    to: "/home/reviewer",
    roles: ["REVIEWER"],
  },
  {
    label: "Workspace",
    to: "/home/group-leader",
    roles: ["GROUP_LEADER"],
  },
  {
    label: "Workspace",
    to: "/home/member",
    roles: ["MEMBER"],
  },
  {
    label: "Active Cycles",
    to: "/member/cycles",
    roles: ["MEMBER"],
  },
  {
    label: "Listings",
    to: "/member/listings",
    roles: ["MEMBER"],
  },
  {
    label: "Notifications",
    to: "/notifications",
    roles: [
      "MEMBER",
      "GROUP_LEADER",
      "REVIEWER",
      "FINANCE_CLERK",
      "ADMINISTRATOR",
    ],
  },
  {
    label: "Finance",
    to: "/finance/dashboard",
    roles: ["FINANCE_CLERK", "ADMINISTRATOR"],
  },
  {
    label: "Blacklist",
    to: "/admin/withdrawal-blacklist",
    roles: ["ADMINISTRATOR"],
  },
];

export const resolveAppNavItems = (roles: RoleName[]): AppNavItem[] =>
  appNavItems.filter((item) => hasAnyRole(roles, item.roles));

import type { NextFunction, Request, Response } from "express";
import type { RoleName } from "../auth/roles";
import { sendError } from "../utils/apiResponse";

export const requireAuth = (request: Request, response: Response, next: NextFunction): void => {
  if (!request.auth) {
    sendError(response, 401, "Authentication required.", "NOT_AUTHENTICATED");
    return;
  }
  next();
};

export const requireRoles = (...allowedRoles: RoleName[]) => {
  return (request: Request, response: Response, next: NextFunction): void => {
    if (!request.auth) {
      sendError(response, 401, "Authentication required.", "NOT_AUTHENTICATED");
      return;
    }

    const hasAllowedRole = request.auth.roles.some((role) =>
      allowedRoles.includes(role),
    );

    if (!hasAllowedRole) {
      sendError(
        response,
        403,
        "You are not authorized for this route.",
        "ROLE_FORBIDDEN",
        { allowedRoles },
      );
      return;
    }

    next();
  };
};

import { Router, type Response } from "express";
import { z } from "zod";
import { requireAuth, requireRoles } from "../../../middleware/rbac";
import { sendError } from "../../../utils/apiResponse";
import {
  addOrReplaceBlacklist,
  getCommissionSummary,
  getReconciliationCsv,
  getWithdrawalBlacklist,
  getWithdrawalEligibility,
  patchBlacklistEntry,
  removeBlacklistEntry,
  requestWithdrawal,
} from "../services/financeService";

const commissionQuerySchema = z.object({
  dateFrom: z.string().date().optional(),
  dateTo: z.string().date().optional(),
});

const withdrawalSchema = z.object({
  amount: z.coerce.number().positive(),
  leaderUserId: z.coerce.number().int().positive().optional(),
});

const blacklistUpsertSchema = z.object({
  userId: z.coerce.number().int().positive(),
  reason: z.string().trim().min(3).max(255),
  active: z.boolean().default(true),
});

const blacklistPatchSchema = z.object({
  reason: z.string().trim().min(3).max(255).optional(),
  active: z.boolean().optional(),
});

const exportQuerySchema = z.object({
  dateFrom: z.string().date(),
  dateTo: z.string().date(),
});

const handleFinanceError = (error: unknown, response: Response): boolean => {
  if (error instanceof z.ZodError) {
    sendError(
      response,
      400,
      "Invalid request payload.",
      "INVALID_REQUEST_PAYLOAD",
      error.issues,
    );
    return true;
  }

  const badRequestErrors = new Set([
    "INVALID_WITHDRAWAL_AMOUNT",
    "WITHDRAWAL_DAILY_LIMIT_EXCEEDED",
    "WITHDRAWAL_WEEKLY_LIMIT_EXCEEDED",
  ]);

  if (error instanceof Error && badRequestErrors.has(error.message)) {
    sendError(response, 400, error.message, error.message);
    return true;
  }

  if (error instanceof Error && error.message === "WITHDRAWAL_NOT_ELIGIBLE") {
    sendError(response, 409, error.message, error.message);
    return true;
  }

  if (
    error instanceof Error &&
    error.message === "LEADER_NOT_ELIGIBLE_FOR_WITHDRAWAL"
  ) {
    sendError(response, 403, error.message, error.message);
    return true;
  }

  return false;
};

export const financeRouter = Router();

financeRouter.get(
  "/finance/commissions",
  requireAuth,
  requireRoles("FINANCE_CLERK", "ADMINISTRATOR"),
  async (request, response, next) => {
    try {
      const query = commissionQuerySchema.parse(request.query);
      const data = await getCommissionSummary(query);
      response.json({ data });
    } catch (error) {
      if (handleFinanceError(error, response)) {
        return;
      }
      next(error);
    }
  },
);

financeRouter.get(
  "/finance/withdrawals/eligibility",
  requireAuth,
  requireRoles("GROUP_LEADER", "FINANCE_CLERK", "ADMINISTRATOR"),
  async (request, response, next) => {
    try {
      const queryLeaderId = z.coerce
        .number()
        .int()
        .positive()
        .optional()
        .parse(request.query.leaderUserId);
      const isFinanceOrAdmin = request.auth!.roles.some((role) =>
        ["FINANCE_CLERK", "ADMINISTRATOR"].includes(role),
      );

      const leaderUserId = queryLeaderId ?? request.auth!.userId;

      if (queryLeaderId && !isFinanceOrAdmin) {
        sendError(
          response,
          403,
          "You are not authorized to review another leader's eligibility.",
          "ROLE_FORBIDDEN",
        );
        return;
      }

      const data = await getWithdrawalEligibility(leaderUserId);
      response.json(data);
    } catch (error) {
      if (handleFinanceError(error, response)) {
        return;
      }
      next(error);
    }
  },
);

financeRouter.post(
  "/finance/withdrawals",
  requireAuth,
  requireRoles("GROUP_LEADER", "FINANCE_CLERK", "ADMINISTRATOR"),
  async (request, response, next) => {
    try {
      const payload = withdrawalSchema.parse(request.body);
      const isFinanceOrAdmin = request.auth!.roles.some((role) =>
        ["FINANCE_CLERK", "ADMINISTRATOR"].includes(role),
      );

      const leaderUserId = payload.leaderUserId ?? request.auth!.userId;

      if (payload.leaderUserId && !isFinanceOrAdmin) {
        sendError(
          response,
          403,
          "You are not authorized to request a withdrawal for another leader.",
          "ROLE_FORBIDDEN",
        );
        return;
      }

      const result = await requestWithdrawal({
        leaderUserId,
        amount: payload.amount,
        requestedByUserId: request.auth!.userId,
      });

      response.status(201).json(result);
    } catch (error) {
      if (handleFinanceError(error, response)) {
        return;
      }
      next(error);
    }
  },
);

