        actorUserId: request.auth!.userId,
      });
      if (!deleted) {
        sendError(response, 404, "Blacklist entry not found.", "BLACKLIST_NOT_FOUND");
        return;
      }
      response.status(204).send();
    } catch (error) {
      if (handleFinanceError(error, response)) {
