import express from "express";
import request from "supertest";

const { loginMock, getCurrentSessionMock, logoutMock } = vi.hoisted(() => ({
  loginMock: vi.fn(),
  getCurrentSessionMock: vi.fn(),
  logoutMock: vi.fn(),
}));

vi.mock("../../src/auth/authService", () => ({
